const articles = Array.isArray($json.articles) ? $json.articles.slice(0, 10) : [];
const headlines = articles.map((article, index) => `${index + 1}. ${article.title}`).join('
');
const prompt = `You are analyzing recent Indian financial news headlines.

Question: Is sentiment bullish or bearish for Indian stock market?

Headlines:
${headlines}

Return strict JSON with:
- sentiment: bullish or bearish
- confidence_score: number between 0 and 1`;
return [{ json: { headlines, article_count: articles.length, prompt } }];

