={{ ({
  model: "gpt-4.1-mini",
  input: [
    {
      role: "system",
      content: [
        {
          type: "input_text",
          text: "You are a market sentiment classifier focused on Indian equities. Based only on the supplied headlines, classify the Indian stock market sentiment as bullish or bearish. Return only valid JSON."
        }
      ]
    },
    {
      role: "user",
      content: [
        {
          type: "input_text",
          text: $json.prompt
        }
      ]
    }
  ],
  text: {
    format: {
      type: "json_schema",
      name: "indian_market_sentiment",
      schema: {
        type: "object",
        properties: {
          sentiment: { type: "string", enum: ["bullish", "bearish"] },
          confidence_score: { type: "number", minimum: 0, maximum: 1 }
        },
        required: ["sentiment", "confidence_score"],
        additionalProperties: false
      }
    }
  }
}) }}

