const raw = $json.output_text ?? $json.output?.[0]?.content?.[0]?.text ?? '';
const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
return [{ json: { sentiment: parsed.sentiment, confidence_score: parsed.confidence_score } }];
